CREATE TABLE 'informix'.cdmclientes (id_usuario INTEGER NOT NULL, id_cliente CHAR(30) NOT NULL, id_ruta CHAR(30) NOT NULL, id_compania CHAR(30), nombre VARCHAR(255) NOT NULL, identificacion VARCHAR(30) NOT NULL, direccion VARCHAR(255), telefono VARCHAR(255), departamento VARCHAR(255), id_estado INTEGER, cobrar_sn CHAR(1) NOT NULL, secuencia INTEGER, observaciones VARCHAR(255), dir_cobro CHAR(1), prog CHAR(1), last_download DATETIME YEAR TO FRACTION(5), tipocliente INTEGER) ;
ALTER TABLE 'informix'.cdmclientes ADD CONSTRAINT ( PRIMARY KEY ( id_cliente, id_usuario ) CONSTRAINT cliente_pk ) ;
